sql:
SELECT title
FROM literary_works
WHERE year = (SELECT MAX(year) FROM literary_works) - 1;

SELECT author_name
FROM authors
WHERE nationality = 'Turkish';

SELECT title, year, word_count
FROM literary_works
ORDER BY year DESC;

SELECT COUNT(*) AS total_reviews, AVG(rating) AS average_rating
FROM reviews
WHERE work_id = 1;

SELECT AVG(word_count) AS avg_word_count
FROM literary_works
WHERE year = 2020 AND word_count > (
    SELECT AVG(word_count) 
    FROM literary_works
);

SELECT sale_id, work_id, total_revenue
FROM sales
ORDER BY total_revenue DESC;

