- "sown more than one seed" metaphorically refers to having published more than one literary work;
- "fields of literature" represents the literary world or domain;
- "dawn of the new millennium" symbolically refers to the year 2000;
- "fruitful efforts" relates to the count of their works, indicating productivity in writing.

sql:
SELECT AVG(word_count) AS average_word_count
FROM literary_works
WHERE work_id IN (
    SELECT work_id FROM literary_works WHERE year = 2021
    UNION
    SELECT work_id FROM literary_works WHERE co_author_id IN (
        SELECT author_id FROM literary_works WHERE year = 2021
    )
);

SELECT year, COUNT(work_id) AS number_of_works
FROM literary_works
GROUP BY year;

SELECT work_id, COUNT(*) AS review_count
FROM reviews
GROUP BY work_id;

SELECT author_name
FROM authors
WHERE author_id = 0;

SELECT AVG(word_count) AS average_word_count
FROM literary_works
WHERE (author_id = 1 OR co_author_id = 1) AND year > 2020;

SELECT w.title, s.total_revenue
FROM literary_works w
INNER JOIN sales s ON w.work_id = s.work_id;
